/* TrainingCard.jsx */
import React, { useState } from 'react';
import './TrainingCard.css';

function StarRating({ rating }) {
  const r = rating || 0;
  return (
    <div className="tcard__stars">
      {[1,2,3,4,5].map(i => (
        <span key={i} style={{
          color: i <= Math.round(r) ? '#FCD34D' : 'var(--text-muted)',
          fontSize: '0.9rem',
        }}>★</span>
      ))}
      <span style={{ fontWeight: 700, color: '#FCD34D', marginLeft: 4, fontSize: '0.85rem' }}>
        {r.toFixed(1)}
      </span>
    </div>
  );
}

// Category → Picsum seeded images (always loads, free, no auth)
const CATEGORY_IMAGES = {
  'Engineering':   'https://picsum.photos/seed/engineering/600/300',
  'Data Science':  'https://picsum.photos/seed/datascience/600/300',
  'Design':        'https://picsum.photos/seed/uxdesign/600/300',
  'DevOps':        'https://picsum.photos/seed/devops/600/300',
  'Marketing':     'https://picsum.photos/seed/marketing/600/300',
  'Finance':       'https://picsum.photos/seed/finance/600/300',
  'Product':       'https://picsum.photos/seed/product/600/300',
  'Web3':          'https://picsum.photos/seed/blockchain/600/300',
};

// Category → accent color for overlay
const CATEGORY_COLOR = {
  'Engineering':  '#C4B5FD',
  'Data Science': '#86EFAC',
  'Design':       '#FCA5A5',
  'DevOps':       '#67E8F9',
  'Marketing':    '#FCD34D',
  'Finance':      '#86EFAC',
  'Product':      '#C4B5FD',
  'default':      '#C4B5FD',
};

export default function TrainingCard({ training, onOpenModal }) {
  const [imgError, setImgError] = useState(false);

  const {
    title        = 'Untitled Course',
    category     = 'General',
    tagColor     = 'lavender',
    level        = 'Beginner',
    description  = '',
    duration     = '',
    price        = 0,
    enrolled     = 0,
    rating       = 0,
    reviews      = 0,
    lessons,
    chapters,
    tags,
    provider,
    featured,
  } = training || {};

  const color     = tagColor || 'lavender';
  const imgSrc    = CATEGORY_IMAGES[category] || `https://picsum.photos/seed/${category}/600/300`;
  const accentColor = CATEGORY_COLOR[category] || CATEGORY_COLOR['default'];

  return (
    <div className="tcard" onClick={() => onOpenModal && onOpenModal(training)}
      style={{ cursor: 'pointer' }}>

      {/* ── THUMBNAIL ── */}
      <div className="tcard__thumb">
        {!imgError ? (
          <img
            src={imgSrc}
            alt={title}
            className="tcard__thumb-img"
            onError={() => setImgError(true)}
          />
        ) : (
          /* Fallback gradient if image fails */
          <div className="tcard__thumb-fallback"
            style={{ background: `linear-gradient(135deg, ${accentColor}22, ${accentColor}08)` }}>
            <span style={{ fontSize:'3rem', opacity:0.3 }}>🎓</span>
          </div>
        )}

        {/* Overlay */}
        <div className="tcard__thumb-overlay-img" />

        {/* Top badges */}
        <div className="tcard__thumb-top">
          <span className={`tcard__cat-badge tcard__cat-badge--${color}`}>
            {category}
          </span>
          {featured && (
            <span className="tcard__popular-badge">⚡ Popular</span>
          )}
        </div>

        {/* Bottom row */}
        <div className="tcard__thumb-bottom">
          <span className="tcard__level-badge">{level}</span>
          <span className="tcard__play-btn">▶ Preview</span>
        </div>
      </div>

      {/* ── BODY ── */}
      <div className="tcard__body">
        <h4 className="tcard__title">{title}</h4>

        {(provider || category) && (
          <p className="tcard__provider">{provider || category}</p>
        )}

        {description && (
          <p className="tcard__desc">
            {description.length > 85 ? description.slice(0, 85) + '…' : description}
          </p>
        )}

        {/* Stats */}
        <div className="tcard__meta-row">
          {duration  && <span className="tcard__meta-item"><span className="tcard__meta-icon">⏱</span>{duration}</span>}
          {lessons > 0 && <span className="tcard__meta-item"><span className="tcard__meta-icon">📚</span>{lessons} lessons</span>}
          {chapters > 0 && <span className="tcard__meta-item"><span className="tcard__meta-icon">📂</span>{chapters} chapters</span>}
        </div>

        <div className="tcard__rating-row">
          <StarRating rating={rating} />
          <span className="tcard__reviews">({(reviews || 0).toLocaleString()})</span>
        </div>

        {/* Footer */}
        <div className="tcard__footer">
          <div className="tcard__price-wrap">
            {price === 0
              ? <span className="tcard__free">🆓 Free</span>
              : <span className="tcard__price">₹{price.toLocaleString()}</span>
            }
            <span className="tcard__enrolled-count">
              👥 {enrolled >= 1000 ? `${(enrolled/1000).toFixed(1)}k` : enrolled} enrolled
            </span>
          </div>
          <span className="tcard__cta">View →</span>
        </div>
      </div>
    </div>
  );
}
